import type { User } from '@sentry/vue'
import type { Mixpanel } from 'mixpanel-browser'

interface AnalyticsMessage {
  type: 'analytics'
  fn: keyof Mixpanel
  args: any[]
}

export async function useAnalyticsHandler() {
  const { default: mixpanel } = await import('mixpanel-browser')

  mixpanel.init('085f8b3d3a8befd9250a6c65d7cf086c', {
    debug: import.meta.env.DEV,
    verbose: true,
    ignore_dnt: true
  })

  chrome.runtime.onMessage.addListener((message: AnalyticsMessage) => {
    const { type, fn, args } = message ?? {}

    if (type === 'analytics') {
      // Skip duplicate identify
      if (fn === 'identify' && args[0] === mixpanel.get_distinct_id())
        return

      console.log(`Analytics: ${fn}`, { args });
      (mixpanel as any)[fn](...args)
    }
  })

  console.log('Analytics(mixpanel): init')
}

export class Analytics {
  // @ts-expect-error type issue
  static #run<Fn extends keyof Mixpanel>(fn: Fn, args: Parameters<Mixpanel[Fn]>) {
    return chrome.runtime.sendMessage<AnalyticsMessage>({ type: 'analytics', fn, args })
  }

  static identify(user: User) {
    this.#run('identify', [String(user.id)])
  }

  static track(key: string, data?: object) {
    this.#run('track', [key, data])
  }
}
