import type { Menus } from 'wxt/browser'

function createContextMenu(list: Menus.CreateCreatePropertiesType[]) {
  const listeners: Record<string, Menus.CreateCreatePropertiesType['onclick']> = {}

  const items = list.map((entry) => {
    entry.id ??= crypto.randomUUID()

    if (entry.onclick) {
      listeners[entry.id] = entry.onclick

      delete entry.onclick
    }

    return entry
  })

  // Register menu items
  items.forEach(props => browser.contextMenus.create(props))

  // Listen to clicks
  browser.contextMenus.onClicked.addListener((info, tab) => {
    const { menuItemId: id } = info
    if (id in listeners)
      listeners[id]?.(info, tab!)
  })
}

// Register context menu items
export function registerContextMenu() {
  createContextMenu([
    // #region Help
    {
      title: 'đź—¨ď¸Ź Help',
      id: 'help-group',
      contexts: ['action']
    },
    {
      title: 'Contact us',
      id: 'help-group-contact',
      parentId: 'help-group',
      contexts: ['action'],
      onclick: () => browser.tabs.create({ url: 'mailto:support@autogmail.com' })
    },
    // #endregion Help

    // #region Troubleshoot
    {
      title: 'đź”§ Troubleshoot',
      id: 'troubleshooter-group',
      contexts: ['action']
    },
    {
      title: 'Reload',
      id: 'troubleshooter-group-reload',
      parentId: 'troubleshooter-group',
      contexts: ['action'],
      onclick: () => reloadApp()
    },
    {
      title: 'Hard reset (removes all synced data)',
      id: 'troubleshooter-group-reset',
      parentId: 'troubleshooter-group',
      contexts: ['action'],
      async onclick() {
        await Promise.all([
          browser.storage.session.clear(),
          browser.storage.local.clear(),
          browser.storage.sync.clear()
        ])

        browser.runtime.reload()
      }
    }
    // #endregion Troubleshoot
  ])
}
