import type { Tabs } from 'wxt/browser'
import { registerContextMenu } from './context-menu'
import '@inboxsdk/core/background'

async function openPopup(tab?: Tabs.Tab) {
  if (!tab) {
    const list = await browser.tabs.query({ active: true, currentWindow: true })
    tab = list[0]
  }

  await browser.action.setPopup({
    popup: browser.runtime.getURL('/popup-view.html'),
    tabId: tab.id
  })

  await browser.action.openPopup()
}

export default defineBackground(() => {
  const isChrome = !navigator.userAgent.includes('Firefox')

  // Analytics proxy
  registerContextMenu()
  useAnalyticsHandler()

  // Open Gmail on install
  browser.runtime.onInstalled.addListener((details) => {
    // Only open gmail on fresh install
    if (details.reason === chrome.runtime.OnInstalledReason.INSTALL) {
      browser.tabs.create({
        active: true,
        url: 'https://mail.google.com'
      })
    }

    if (import.meta.env.DEV)
      browser.tabs.create({ active: true, url: getRouteURL('/') })
  })

  // Listen for events
  browser.runtime.onMessage.addListener((message, _sender) => {
    if (message === 'open-popup')
      openPopup()

    return undefined
  })

  // Open gmail page when click event is passed to action button
  browser.action.onClicked.addListener(async () => {
    const [tab] = await browser.tabs.query({ url: '*://mail.google.com/*', currentWindow: true })
    let [currentTab] = await browser.tabs.query({ active: true, currentWindow: true })
    const isGmailPage = currentTab.url?.includes('://mail.google.com')

    if (!isGmailPage) {
      currentTab = (tab && tab.id)
        ? await browser.tabs.update(tab.id, { active: true })
        : await browser.tabs.create({ url: 'https://mail.google.com', active: true })
    }

    await openPopup(currentTab)
  })

  if (isChrome) {
    // Set uninstall url
    chrome.identity.getProfileUserInfo((user) => {
      chrome.runtime.setUninstallURL(
        `https://app.vocal.email/collect/auto-gmail?email=${user.email}`
      )
    })
  }
})
