import { sanitize as sanitizeEmail } from 'lettersanitizer'
import { z } from 'zod'
import { http } from './core'

export namespace User {
  export const Model = z.object({
    id: z.coerce.number(),
    email: z.string().email(),
    subscribed: z.coerce.boolean(),

    /** HTML signature snippet */
    signature: z.string().nullable().default(''),

    /** The context the user passes to the AI */
    context: z.coerce.string().default(''),

    /** If gmail account is connected */
    connected: z.boolean().default(false),

    /** If gmail account needs reauth */
    connection_error: z.coerce.boolean().default(false),

    /** If the AI is enabled for the user */
    enabled: z.boolean().default(false),

    /** List of blocked email addresses */
    blacklist: z.string().array().default([]),

    /** AI tips learned for the user */
    ai_tips: z.string().array().default([]),

    appsumo: z.object({
      plan: z.number(),
      count: z.number()
    }).nullable().default(null)
  })

  /** Auth account model */
  export const AccountModel = z.object({
    accessToken: z.string(),
    refreshToken: z.string(),

    id: z.string(),
    name: z.string().nullable().default('You'),
    email: z.string().email(),

    data: Model
  })

  export type IModel = z.infer<typeof Model>
  export type IAccountModel = z.infer<typeof AccountModel>

  /** Returns user data */
  export function get() {
    return http.get('/chrome-account').json(Model.parse)
  }
}

export namespace Signature {
  interface Response {
    signature: string | null
    success: boolean
  }

  /** ID used when appending html signature */
  export const ELEMENT_ID = 'autogmail-user-signature-wrapper'

  export function append<T extends Element | string>(input: T, content: string): T {
    const target = remove(input)

    const sanitizedContent = sanitize(content, { collapseLines: true })
    const snippet = `<div id="${ELEMENT_ID}">${sanitizedContent}</div>`

    if (typeof target === 'string')
      return target + snippet as T

    target.innerHTML += snippet
    return target
  }

  /** Removes all appended signature including native Gmail signatures */
  export function remove<T extends Element | string>(content: T): T {
    function strip(el: Element) {
      // Remove signature element
      const refs = [
        ...el.querySelectorAll(`[id$="${ELEMENT_ID}"]`), // AutoGmail signatures
        ...el.querySelectorAll('.gmail_signature') // Native signatures
      ]

      refs.forEach(i => i.remove())
      return el
    }

    if (typeof content === 'string') {
      const node = document.createElement('div')
      node.innerHTML = content

      return strip(node).innerHTML as T
    }

    return strip(content) as T
  }

  /** Returns AutoGmail watermark html snippet */
  export function getWatermark() {
    return `
      <a
        inert="true"
        contenteditable="false"
        style="display: flex;align-items: center;margin-top: 20px;text-decoration: none;padding: 8px 12px;border: 1px solid #00000026;border-radius: 6px;width: max-content;color: black;font-family: Outfit, Inter, 'Google Sans', sans-serif;"
        href="https://chromewebstore.google.com/detail/auto-gmail-chatgpt-ai-for/idcjeikbgickhefaljahoafgpmjdcmed" target="_blank">
        <img src="https://files.umso.co/lib_pWaLHdCpwCbXGFRQ/lzovejz2k9kdsusc.png" alt="" width="24" height="24" style="border-radius: 6px;margin-right: 8px;">
        <span style="margin: auto 0px;">Drafted with the assistance of Auto Gmail</span>
      </a>
      `.replaceAll(/\n/g, ' ')
  }

  export function sanitize(input: string | null, { collapseLines = false } = {}) {
    if (!input)
      return null

    let content = sanitizeEmail(input, undefined, { noWrapper: true })

    if (collapseLines)
      content = content.replace(/\n/g, '').trim()

    return content
  }

  export async function upload(file: File) {
    const result = await http.formData({
      signature: file
    })
      .post(undefined, '/signature')
      .json<Response>()

    result.signature = await sanitize(result.signature)
    return result
  }
}

export namespace Drafts {
  const PayloadModelContact = z.object({
    name: z.string().nullish(),
    emailAddress: z.coerce.string()
  })

  export const PayloadModel = z.object({
    threadID: z.string(),
    subject: z.string(),

    /** User defined message to affect the result */
    customMessage: z.string().optional(),

    /** Current user draft. Passed along with [customMessage] */
    draft: z.string().optional(),

    recipients: PayloadModelContact.array(),

    /** Messages of email thread */
    messages: z.object({
      /** ID of reply email message */
      id: z.string(),

      /** Whether message was sent by user */
      isSender: z.boolean(),

      sender: PayloadModelContact,

      date: z.coerce.date(),
      text: z.string()
    }).array()
  })

  export const ImportEmailModel = z.object({
    messageID: z.string().nullable(),
    emailID: z.string(),
    threadID: z.string(),
    subject: z.string(),
    sender: z.string().email(),
    recipients: PayloadModelContact.array(),
    body: z.string()
  })

  export type IPayloadModel = z.infer<typeof PayloadModel>
  export type IImportEmailModel = z.infer<typeof ImportEmailModel>

  export interface GenerateResponse {
    add_watermark: boolean
    drafts: string[]
    signature?: string

    error?: HintedString<'upgrade_required'>
    message?: string
  }

  export const AI_DRAFT_CONTENT_ID = 'auto-gmail-draft'

  /** Checks if element has draft generated by AutoGmail */
  export function hasAIDraft(el: Element) {
    return el.querySelector(`[id$="${AI_DRAFT_CONTENT_ID}"]`) !== null
  }

  /** Returns array of draft messages */
  export async function generate(data: IPayloadModel, { signature = '' } = {}): Promise<GenerateResponse> {
    const result = await http
      .post({ data }, `/generate-drafts`)
      .json<GenerateResponse>()

    // Normalize
    result.drafts ??= []
    result.add_watermark ??= false

    // Append signature and branding to drafts
    const drafts = result.drafts.map((draft) => {
      if (result.signature)
        draft = Signature.append(draft, signature || result.signature)

      if (result.add_watermark)
        draft += Signature.getWatermark()

      return `<span id="${AI_DRAFT_CONTENT_ID}">${draft}</span>`
    })

    console.debug('Generated drafts', {
      original: result,
      drafts
    })

    return { ...result, drafts }
  }

  export function importEmail(data: IImportEmailModel) {
    return http
      .post(ImportEmailModel.parse(data), `/import-email`)
      .json<{ success: boolean }>()
      .then(i => i.success)
  }
}

export namespace Blacklist {
  interface GetResult {
    blacklisted: string[]
    list: string[]
  }

  interface UpdateResult {
    success: boolean
    error?: string

    result: 'added' | 'removed'
    email: string
  }

  /** Returns user blacklist */
  export async function get() {
    const result = await http.get('/chrome-blacklist')
      .json<GetResult>()

    return result.blacklisted
  }

  /** Adds/Removes email to blacklist */
  export async function toggle(email: string) {
    return http
      .post({ email }, '/chrome-blacklist')
      .json<UpdateResult>()
  }
}
