import type { RouteNamedMap } from 'vue-router/auto-routes'
import { API_BASE } from '@/src/http'

/** Returns path of chrome page */
export function getRouteURL(path: HintedString<keyof RouteNamedMap>, params?: Record<string, any>) {
  let url = browser.runtime.getURL(`/views.html#${path}`)

  if (params) {
    const searchParams = new URLSearchParams('')

    for (const key in params) {
      searchParams.set(key, `${params[key]}`)
    }

    url += `?${searchParams.toString()}`
  }

  return url
}

/** Returns full url of backend api */
export function getAPIURL(path: string) {
  return new URL(path, API_BASE).href
}

/** Reloads all gmail pages and the extension itself */
export async function reloadApp() {
  const tabs = await browser.tabs.query({ url: '*://mail.google.com/*' })

  browser.runtime.reload()

  for (const tab of tabs) {
    if (tab.id)
      browser.tabs.reload(tab.id)
  }
}
